+/**
+ * Compute a ruLake bundle's `rvf_witness` from Node, byte-for-byte
+ * compatible with `src/bundle.rs::compute_witness` in the Rust crate.
+ *
+ * The witness is a SHAKE-256(32 bytes) hex digest over a stable,
+ * length-prefixed concatenation of the witnessed bundle fields, with a
+ * domain-separating prefix.
+ *
+ *   SHAKE-256(32) of:
+ *       "rulake-bundle-witness-v1|"
+ *       || u64_le(len(data_ref))
+ *       || data_ref bytes
+ *       || "|"
+ *       || u64_le(dim)
+ *       || u64_le(rotation_seed)
+ *       || u64_le(rerank_factor)
+ *       || "|"
+ *       || u64_le(len(generation_bytes))
+ *       || generation_bytes
+ *
+ *   generation_bytes:
+ *       Num(n)     → 0x00 || u64_le(n)             (9 bytes)
+ *       Opaque(s)  → 0x01 || utf8(s)
+ *
+ * The leading variant tag byte (0x00/0x01) was added on 2026-04-23 to
+ * close the `Num(7)` vs `Opaque("\x07\0…")` collision; the witness
+ * format version is therefore 2.
+ */
+
+import { shake256 } from "@noble/hashes/sha3";
+import { bytesToHex } from "@noble/hashes/utils";
+
+import type { Generation, RuLakeBundle } from "./bundle.js";
+
+/** Encode a u64 (BigInt or small number) as 8 little-endian bytes. */
+export function u64LE(n: bigint | number): Buffer {
+  const v = typeof n === "bigint" ? n : BigInt(n);
+  if (v < 0n || v > 0xffff_ffff_ffff_ffffn) {
+    throw new Error(`u64LE: ${v} out of u64 range`);
+  }
+  const out = Buffer.alloc(8);
+  out.writeBigUInt64LE(v);
+  return out;
+}
+
+/**
+ * Serialize a `Generation` to its witness-input byte form.
+ *
+ * Mirrors `Generation::hash_bytes()` in `src/bundle.rs`:
+ *   - `Num(n)`    → 0x00 || u64_le(n)        (9 bytes)
+ *   - `Opaque(s)` → 0x01 || UTF-8(s)
+ */
+export function generationBytes(g: Generation): Buffer {
+  if (g.kind === "Num") {
+    return Buffer.concat([Buffer.from([0x00]), u64LE(g.value)]);
+  }
+  return Buffer.concat([Buffer.from([0x01]), Buffer.from(g.value, "utf8")]);
+}
+
+/**
+ * The lower-level witness function. Takes the raw witnessed inputs and
+ * returns the lowercase hex SHAKE-256(32) digest. Useful when you have
+ * the fields in hand without a full bundle (e.g. a builder).
+ */
+export function computeWitness(args: {
+  dataRef: string;
+  dim: number | bigint;
+  rotationSeed: bigint | number;
+  rerankFactor: number | bigint;
+  generation: Generation;
+}): string {
+  const dataRefBytes = Buffer.from(args.dataRef, "utf8");
+  const genBytes = generationBytes(args.generation);
+
+  const buf = Buffer.concat([
+    Buffer.from("rulake-bundle-witness-v1|", "utf8"),
+    u64LE(BigInt(dataRefBytes.length)),
+    dataRefBytes,
+    Buffer.from("|", "utf8"),
+    u64LE(args.dim),
+    u64LE(args.rotationSeed),
+    u64LE(args.rerankFactor),
+    Buffer.from("|", "utf8"),
+    u64LE(BigInt(genBytes.length)),
+    genBytes,
+  ]);
+
+  // dkLen=32 → 32-byte XOF output, hex-encoded → 64 chars lowercase.
+  const digest = shake256(buf, { dkLen: 32 });
+  return bytesToHex(digest);
+}
+
+/**
+ * Recompute a parsed bundle's witness from its other fields and report
+ * whether it matches the on-disk `rvf_witness`.
+ */
+export function verifyBundle(bundle: RuLakeBundle): {
+  ok: boolean;
+  expected: string;
+  actual: string;
+} {
+  const expected = computeWitness({
+    dataRef: bundle.data_ref,
+    dim: bundle.dim,
+    rotationSeed: bundle.rotation_seed,
+    rerankFactor: bundle.rerank_factor,
+    generation: bundle.generation,
+  });
+  return { ok: expected === bundle.rvf_witness, expected, actual: bundle.rvf_witness };
+}

@@ -0,0 +1,226 @@
+/**
+ * Tests for the Node implementation of the ruLake bundle witness.
+ *
+ * The most important test is the cross-language fixture round-trip: we
+ * load a `table.rulake.json` produced by the Rust crate and assert
+ * that our recomputed witness matches the one Rust wrote. If this
+ * fails, the byte stream layout has drifted and the Node code is
+ * BROKEN — do not ship it.
+ */
+
+import { readFileSync } from "node:fs";
+import { fileURLToPath } from "node:url";
+import { dirname, resolve } from "node:path";
+
+import { describe, expect, it } from "vitest";
+
+import { parseBundle, MAX_BUNDLE_BYTES, MAX_FIELD_BYTES } from "../src/bundle.js";
+import { computeWitness, generationBytes, u64LE, verifyBundle } from "../src/witness.js";
+
+const __filename = fileURLToPath(import.meta.url);
+const __dirname = dirname(__filename);
+const FIXTURE = resolve(__dirname, "../fixtures/known-good-bundle.json");
+
+describe("u64LE", () => {
+  it("encodes 0 as 8 zero bytes", () => {
+    expect([...u64LE(0n)]).toEqual([0, 0, 0, 0, 0, 0, 0, 0]);
+  });
+
+  it("encodes 7 as little-endian", () => {
+    // 7 → [0x07, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00, 0x00]
+    expect([...u64LE(7n)]).toEqual([7, 0, 0, 0, 0, 0, 0, 0]);
+  });
+
+  it("rejects out-of-range values", () => {
+    expect(() => u64LE(-1n)).toThrow(/out of u64 range/);
+    expect(() => u64LE(0x1_0000_0000_0000_0000n)).toThrow(/out of u64 range/);
+  });
+
+  it("handles full u64", () => {
+    expect([...u64LE(0xffff_ffff_ffff_ffffn)]).toEqual([255, 255, 255, 255, 255, 255, 255, 255]);
+  });
+});
+
+describe("generationBytes", () => {
+  it("tags Num with 0x00", () => {
+    const b = generationBytes({ kind: "Num", value: 7n });
+    expect(b.length).toBe(9);
+    expect(b[0]).toBe(0x00);
+    expect([...b.subarray(1)]).toEqual([7, 0, 0, 0, 0, 0, 0, 0]);
+  });
+
+  it("tags Opaque with 0x01", () => {
+    const b = generationBytes({ kind: "Opaque", value: "abc" });
+    expect(b.length).toBe(4);
+    expect(b[0]).toBe(0x01);
+    expect(b.toString("utf8", 1)).toBe("abc");
+  });
+});
+
+describe("computeWitness", () => {
+  it("is deterministic for identical inputs", () => {
+    const a = computeWitness({
+      dataRef: "gs://bucket/x.parquet",
+      dim: 128,
+      rotationSeed: 42n,
+      rerankFactor: 20,
+      generation: { kind: "Num", value: 7n },
+    });
+    const b = computeWitness({
+      dataRef: "gs://bucket/x.parquet",
+      dim: 128,
+      rotationSeed: 42n,
+      rerankFactor: 20,
+      generation: { kind: "Num", value: 7n },
+    });
+    expect(a).toBe(b);
+    expect(a).toHaveLength(64);
+    expect(a).toMatch(/^[0-9a-f]{64}$/);
+  });
+
+  it("changes when any input field changes", () => {
+    const base = {
+      dataRef: "gs://bucket/x.parquet",
+      dim: 128,
+      rotationSeed: 42n,
+      rerankFactor: 20,
+      generation: { kind: "Num" as const, value: 7n },
+    };
+    const w0 = computeWitness(base);
+    expect(w0).not.toBe(computeWitness({ ...base, dataRef: "gs://bucket/y.parquet" }));
+    expect(w0).not.toBe(computeWitness({ ...base, dim: 256 }));
+    expect(w0).not.toBe(computeWitness({ ...base, rotationSeed: 43n }));
+    expect(w0).not.toBe(computeWitness({ ...base, rerankFactor: 5 }));
+    expect(w0).not.toBe(
+      computeWitness({ ...base, generation: { kind: "Num", value: 8n } }),
+    );
+  });
+
+  // Regression: the 2026-04-23 audit found that without the variant tag
+  // byte, Num(7) and Opaque("\x07\0\0\0\0\0\0\0") shared hash-input
+  // bytes. The Rust fix added a leading 0x00/0x01 tag; this Node port
+  // MUST honor it or it will miscompute witnesses for any v2 bundle
+  // whose backend reports an Opaque token.
+  it("Num(7) and Opaque('\\x07\\0\\0\\0\\0\\0\\0\\0') do not collide (audit regression)", () => {
+    const wNum = computeWitness({
+      dataRef: "x",
+      dim: 1,
+      rotationSeed: 0n,
+      rerankFactor: 1,
+      generation: { kind: "Num", value: 7n },
+    });
+    const wOpaque = computeWitness({
+      dataRef: "x",
+      dim: 1,
+      rotationSeed: 0n,
+      rerankFactor: 1,
+      generation: { kind: "Opaque", value: "\x07\x00\x00\x00\x00\x00\x00\x00" },
+    });
+    expect(wNum).not.toBe(wOpaque);
+  });
+
+  it("length-prefixing prevents 'a|b' vs 'ab|' collisions", () => {
+    const wA = computeWitness({
+      dataRef: "x",
+      dim: 1,
+      rotationSeed: 0n,
+      rerankFactor: 1,
+      generation: { kind: "Opaque", value: "a|b" },
+    });
+    const wB = computeWitness({
+      dataRef: "x",
+      dim: 1,
+      rotationSeed: 0n,
+      rerankFactor: 1,
+      generation: { kind: "Opaque", value: "ab|" },
+    });
+    expect(wA).not.toBe(wB);
+  });
+});
+
+describe("parseBundle", () => {
+  it("rejects oversize bundles", () => {
+    const big = "x".repeat(MAX_BUNDLE_BYTES + 1);
+    expect(() => parseBundle(big)).toThrow(/exceeds .* bytes/);
+  });
+
+  it("rejects oversize string fields", () => {
+    const long = "p".repeat(MAX_FIELD_BYTES + 1);
+    const body = JSON.stringify({
+      format_version: 2,
+      data_ref: "x",
+      dim: 1,
+      rotation_seed: 0,
+      rerank_factor: 1,
+      generation: 1,
+      rvf_witness: "0".repeat(64),
+      pii_policy: long,
+      lineage_id: null,
+    });
+    expect(() => parseBundle(body)).toThrow(/pii_policy/);
+  });
+
+  it("rejects format_version > 2", () => {
+    const body = JSON.stringify({
+      format_version: 99,
+      data_ref: "x",
+      dim: 1,
+      rotation_seed: 0,
+      rerank_factor: 1,
+      generation: 1,
+      rvf_witness: "0".repeat(64),
+      pii_policy: null,
+      lineage_id: null,
+    });
+    expect(() => parseBundle(body)).toThrow(/format_version=99/);
+  });
+
+  it("accepts a numeric Generation as Num", () => {
+    const body = JSON.stringify({
+      format_version: 2,
+      data_ref: "x",
+      dim: 1,
+      rotation_seed: 0,
+      rerank_factor: 1,
+      generation: 5,
+      rvf_witness: "0".repeat(64),
+      pii_policy: null,
+      lineage_id: null,
+    });
+    const b = parseBundle(body);
+    expect(b.generation).toEqual({ kind: "Num", value: 5n });
+  });
+
+  it("accepts a string Generation as Opaque", () => {
+    const body = JSON.stringify({
+      format_version: 2,
+      data_ref: "x",
+      dim: 1,
+      rotation_seed: 0,
+      rerank_factor: 1,
+      generation: "abc-def",
+      rvf_witness: "0".repeat(64),
+      pii_policy: null,
+      lineage_id: null,
+    });
+    const b = parseBundle(body);
+    expect(b.generation).toEqual({ kind: "Opaque", value: "abc-def" });
+  });
+});
+
+describe("Rust fixture round-trip (cross-language witness check)", () => {
+  it("verifies a real Rust-produced table.rulake.json", () => {
+    const raw = readFileSync(FIXTURE, "utf8");
+    const bundle = parseBundle(raw);
+    const result = verifyBundle(bundle);
+    if (!result.ok) {
+      // Print the diagnostic so a future drift is obvious in CI logs.
+      // eslint-disable-next-line no-console
+      console.error(
+        `WITNESS MISMATCH against fixture:\n  expected (Node-recomputed): ${result.expected}\n  actual   (Rust-written):    ${result.actual}`,
+      );
+    }
+    expect(result.ok).toBe(true);
+    expect(result.actual).toBe(result.expected);
+  });
+});

@@ -0,0 +1,188 @@
+/**
+ * TypeScript types and a hardened parser for the ruLake bundle sidecar
+ * (`table.rulake.json`). Mirrors `src/bundle.rs` in the Rust crate.
+ *
+ * The DoS caps are copied verbatim from the Rust implementation so a
+ * malicious bundle cannot force a Node reader to allocate an unbounded
+ * amount of memory:
+ *
+ *   - whole bundle JSON  ≤ 64 KiB
+ *   - each string field  ≤  4 KiB
+ *   - rvf_witness        ≤  128 chars (real value is exactly 64 hex)
+ *   - format_version     ≤  2
+ */
+
+/** Maximum bundle size in bytes — matches Rust `MAX_JSON_BYTES`. */
+export const MAX_BUNDLE_BYTES = 64 * 1024;
+/** Maximum per-field size in bytes — matches Rust `MAX_FIELD_BYTES`. */
+export const MAX_FIELD_BYTES = 4 * 1024;
+/** Highest `format_version` this Node reader understands. */
+export const MAX_FORMAT_VERSION = 2;
+
+/**
+ * `Generation` — a backend's coherence token at bundle-emission time.
+ *
+ * Serializes as untagged JSON (matches Rust `#[serde(untagged)]`):
+ *   - numeric  → a JSON number that fits in u64
+ *   - opaque   → a JSON string
+ */
+export type Generation = { kind: "Num"; value: bigint } | { kind: "Opaque"; value: string };
+
+/** Parsed shape of `table.rulake.json` after validation. */
+export interface RuLakeBundle {
+  format_version: number;
+  data_ref: string;
+  dim: number;
+  rotation_seed: bigint;
+  rerank_factor: number;
+  generation: Generation;
+  rvf_witness: string;
+  pii_policy: string | null;
+  lineage_id: string | null;
+  /** Optional in the Rust struct — `skip_serializing_if = "Option::is_none"`. */
+  memory_class?: string | null;
+}
+
+/** Coerce `unknown` to a finite non-negative integer or throw. */
+function asNonNegativeInteger(v: unknown, field: string, max?: number): number {
+  if (typeof v !== "number" || !Number.isFinite(v) || !Number.isInteger(v) || v < 0) {
+    throw new Error(`bundle parse: ${field} must be a non-negative integer (got ${String(v)})`);
+  }
+  if (max !== undefined && v > max) {
+    throw new Error(`bundle parse: ${field} ${v} exceeds ${max}`);
+  }
+  return v;
+}
+
+/** Coerce `unknown` to a u64 bigint or throw. */
+function asU64(v: unknown, field: string): bigint {
+  if (typeof v === "number") {
+    if (!Number.isFinite(v) || !Number.isInteger(v) || v < 0) {
+      throw new Error(`bundle parse: ${field} must be a non-negative integer (got ${v})`);
+    }
+    if (v > Number.MAX_SAFE_INTEGER) {
+      throw new Error(
+        `bundle parse: ${field}=${v} exceeds Number.MAX_SAFE_INTEGER; serialize as a JSON string instead`,
+      );
+    }
+    return BigInt(v);
+  }
+  // Some publishers may emit u64 as a string to dodge JSON's 53-bit limit.
+  if (typeof v === "string" && /^\d+$/.test(v)) {
+    const n = BigInt(v);
+    if (n < 0n || n > 0xffff_ffff_ffff_ffffn) {
+      throw new Error(`bundle parse: ${field} ${v} out of u64 range`);
+    }
+    return n;
+  }
+  throw new Error(`bundle parse: ${field} must be a u64 (number or numeric string), got ${typeof v}`);
+}
+
+/** Coerce `unknown` to an optional string ≤ MAX_FIELD_BYTES. */
+function asOptionalString(v: unknown, field: string): string | null {
+  if (v === null || v === undefined) return null;
+  if (typeof v !== "string") {
+    throw new Error(`bundle parse: ${field} must be a string or null`);
+  }
+  if (Buffer.byteLength(v, "utf8") > MAX_FIELD_BYTES) {
+    throw new Error(`bundle parse: ${field} exceeds ${MAX_FIELD_BYTES} bytes`);
+  }
+  return v;
+}
+
+function parseGeneration(v: unknown): Generation {
+  // Untagged: a JSON number is `Num`, a JSON string is `Opaque`.
+  if (typeof v === "number") {
+    return { kind: "Num", value: asU64(v, "generation") };
+  }
+  if (typeof v === "string") {
+    if (Buffer.byteLength(v, "utf8") > MAX_FIELD_BYTES) {
+      throw new Error(`bundle parse: generation (Opaque) exceeds ${MAX_FIELD_BYTES} bytes`);
+    }
+    return { kind: "Opaque", value: v };
+  }
+  // Some Rust enum encodings might also emit a tagged form. Be tolerant.
+  if (v && typeof v === "object") {
+    const obj = v as Record<string, unknown>;
+    if ("Num" in obj) return { kind: "Num", value: asU64(obj.Num, "generation.Num") };
+    if ("Opaque" in obj) {
+      if (typeof obj.Opaque !== "string") {
+        throw new Error("bundle parse: generation.Opaque must be a string");
+      }
+      return parseGeneration(obj.Opaque);
+    }
+  }
+  throw new Error(`bundle parse: generation must be a number or string, got ${typeof v}`);
+}
+
+/**
+ * Parse a `table.rulake.json` payload into a validated `RuLakeBundle`.
+ *
+ * Throws `Error` (with a `bundle parse:` prefix) on any cap violation,
+ * malformed JSON, or unknown future format version.
+ */
+export function parseBundle(raw: string): RuLakeBundle {
+  if (Buffer.byteLength(raw, "utf8") > MAX_BUNDLE_BYTES) {
+    throw new Error(`bundle parse: exceeds ${MAX_BUNDLE_BYTES} bytes`);
+  }
+
+  let json: unknown;
+  try {
+    json = JSON.parse(raw);
+  } catch (err) {
+    throw new Error(`bundle parse: invalid JSON: ${(err as Error).message}`);
+  }
+
+  if (!json || typeof json !== "object" || Array.isArray(json)) {
+    throw new Error("bundle parse: top-level value must be a JSON object");
+  }
+  const o = json as Record<string, unknown>;
+
+  const format_version = asNonNegativeInteger(o.format_version, "format_version");
+  if (format_version > MAX_FORMAT_VERSION) {
+    throw new Error(
+      `bundle parse: format_version=${format_version} newer than this reader supports (${MAX_FORMAT_VERSION})`,
+    );
+  }
+
+  const data_ref = (() => {
+    const v = o.data_ref;
+    if (typeof v !== "string") throw new Error("bundle parse: data_ref must be a string");
+    if (Buffer.byteLength(v, "utf8") > MAX_FIELD_BYTES) {
+      throw new Error(`bundle parse: data_ref exceeds ${MAX_FIELD_BYTES} bytes`);
+    }
+    return v;
+  })();
+
+  const dim = asNonNegativeInteger(o.dim, "dim");
+  const rotation_seed = asU64(o.rotation_seed, "rotation_seed");
+  const rerank_factor = asNonNegativeInteger(o.rerank_factor, "rerank_factor");
+  const generation = parseGeneration(o.generation);
+
+  const rvf_witness = (() => {
+    const v = o.rvf_witness;
+    if (typeof v !== "string") throw new Error("bundle parse: rvf_witness must be a string");
+    if (v.length > 128) {
+      throw new Error("bundle parse: rvf_witness not a hex-encoded SHAKE-256(32)");
+    }
+    return v;
+  })();
+
+  const pii_policy = asOptionalString(o.pii_policy, "pii_policy");
+  const lineage_id = asOptionalString(o.lineage_id, "lineage_id");
+  const memory_class =
+    "memory_class" in o ? asOptionalString(o.memory_class, "memory_class") : undefined;
+
+  return {
+    format_version,
+    data_ref,
+    dim,
+    rotation_seed,
+    rerank_factor,
+    generation,
+    rvf_witness,
+    pii_policy,
+    lineage_id,
+    ...(memory_class !== undefined ? { memory_class } : {}),
+  };
+}

